import{_ as t,o as a,c as r,a2 as o}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"Droid ‚Äî Benchmarks","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/droid/benchmarks.md","filePath":"research/agents/droid/benchmarks.md"}'),i={name:"research/agents/droid/benchmarks.md"};function n(s,e,d,l,c,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="droid-‚Äî-benchmarks" tabindex="-1">Droid ‚Äî Benchmarks <a class="header-anchor" href="#droid-‚Äî-benchmarks" aria-label="Permalink to &quot;Droid ‚Äî Benchmarks&quot;">‚Äã</a></h1><blockquote><p>Terminal-Bench scores, enterprise productivity metrics, and what they reveal about Droid&#39;s model-agnostic performance.</p></blockquote><h2 id="terminal-bench-2-0" tabindex="-1">Terminal-Bench 2.0 <a class="header-anchor" href="#terminal-bench-2-0" aria-label="Permalink to &quot;Terminal-Bench 2.0&quot;">‚Äã</a></h2><p>Terminal-Bench is a benchmark for evaluating terminal-based coding agents on real-world software engineering tasks. Droid appears with multiple model configurations, demonstrating its model-agnostic architecture.</p><h3 id="droid-scores" tabindex="-1">Droid Scores <a class="header-anchor" href="#droid-scores" aria-label="Permalink to &quot;Droid Scores&quot;">‚Äã</a></h3><table tabindex="0"><thead><tr><th>Model Configuration</th><th>Rank</th><th>Score</th><th>Notes</th></tr></thead><tbody><tr><td>Droid + GPT-5.3-Codex</td><td>#6</td><td>77.3%</td><td>Best Droid result; OpenAI frontier model</td></tr><tr><td>Droid + Claude Opus 4.6</td><td>#16</td><td>69.9%</td><td>Anthropic frontier model</td></tr><tr><td>Droid + GPT-5.2</td><td>#23</td><td>64.9%</td><td>Previous-gen OpenAI model</td></tr></tbody></table><h3 id="analysis" tabindex="-1">Analysis <a class="header-anchor" href="#analysis" aria-label="Permalink to &quot;Analysis&quot;">‚Äã</a></h3><p><strong>Model-agnostic consistency</strong>: Droid achieves competitive scores across different model families. The ~7.4 percentage point spread between its best (GPT-5.3-Codex, 77.3%) and middle (Opus 4.6, 69.9%) results is notable ‚Äî the agent platform adds consistent value regardless of which model powers it.</p><p><strong>Rank #6 with GPT-5.3-Codex</strong>: Placing in the top 6 of Terminal-Bench 2.0 demonstrates that Droid&#39;s agent infrastructure (tool system, context management, task planning) effectively leverages frontier model capabilities.</p><p><strong>Multi-model presence</strong>: Having three entries in a single benchmark leaderboard is unusual. Most agents appear once (optimized for their best model). Droid&#39;s multiple entries reflect its vendor-agnostic positioning and provide useful signal about how much the agent platform vs. the underlying model contributes to performance.</p><h2 id="terminal-bench-1-0" tabindex="-1">Terminal-Bench 1.0 <a class="header-anchor" href="#terminal-bench-1-0" aria-label="Permalink to &quot;Terminal-Bench 1.0&quot;">‚Äã</a></h2><table tabindex="0"><thead><tr><th>Model Configuration</th><th>Rank</th><th>Score</th></tr></thead><tbody><tr><td>Droid + Claude Opus 4.1</td><td>#5</td><td>58.8%</td></tr></tbody></table><p>The improvement from 58.8% (TB 1.0) to 77.3% (TB 2.0) reflects both model improvements (Opus 4.1 ‚Üí GPT-5.3-Codex) and likely agent platform improvements over time.</p><h2 id="enterprise-productivity-metrics" tabindex="-1">Enterprise Productivity Metrics <a class="header-anchor" href="#enterprise-productivity-metrics" aria-label="Permalink to &quot;Enterprise Productivity Metrics&quot;">‚Äã</a></h2><p>Factory reports enterprise-level productivity benchmarks from customer deployments. These are not synthetic benchmarks but claimed real-world outcomes:</p><table tabindex="0"><thead><tr><th>Metric</th><th>Value</th><th>Context</th></tr></thead><tbody><tr><td>Feature delivery speed</td><td><strong>7x faster</strong></td><td>End-to-end from task to merge</td></tr><tr><td>Migration time reduction</td><td><strong>96.1% reduction</strong></td><td>Time to complete codebase migrations</td></tr><tr><td>On-call resolution time</td><td><strong>95.8% time saved</strong></td><td>Incident response and fix deployment</td></tr></tbody></table><h3 id="chainguard-case-study-metrics" tabindex="-1">Chainguard Case Study Metrics <a class="header-anchor" href="#chainguard-case-study-metrics" aria-label="Permalink to &quot;Chainguard Case Study Metrics&quot;">‚Äã</a></h3><table tabindex="0"><thead><tr><th>Metric</th><th>Value</th></tr></thead><tbody><tr><td>Continuous session length</td><td><strong>2 weeks</strong></td></tr><tr><td>Repositories managed</td><td><strong>6</strong></td></tr><tr><td>Packages built</td><td><strong>80</strong></td></tr><tr><td>Pattern: Teach once ‚Üí replicate</td><td><strong>~2 teaching iterations ‚Üí independent execution</strong></td></tr></tbody></table><h2 id="analytics-derived-benchmarks" tabindex="-1">Analytics-Derived Benchmarks <a class="header-anchor" href="#analytics-derived-benchmarks" aria-label="Permalink to &quot;Analytics-Derived Benchmarks&quot;">‚Äã</a></h2><p>Factory Analytics enables organizations to generate their own benchmarks:</p><h3 id="autonomy-ratio" tabindex="-1">Autonomy Ratio <a class="header-anchor" href="#autonomy-ratio" aria-label="Permalink to &quot;Autonomy Ratio&quot;">‚Äã</a></h3><ul><li>Measures tool calls per user message.</li><li>Example: <strong>13x</strong> means 13 autonomous tool calls per human interaction.</li><li>Higher ratios indicate more effective delegation and greater agent autonomy.</li></ul><h3 id="productivity-output-example-org" tabindex="-1">Productivity Output (Example Org) <a class="header-anchor" href="#productivity-output-example-org" aria-label="Permalink to &quot;Productivity Output (Example Org)&quot;">‚Äã</a></h3><p>Factory&#39;s analytics blog post cites example aggregate outputs:</p><ul><li><strong>4,500 files created</strong></li><li><strong>129,000 files edited</strong></li><li><strong>3,500 commits</strong></li><li><strong>484 pull requests</strong></li></ul><p>These are tracked over time and correlated with adoption curves ‚Äî as teams ramp up Droid usage, code output increases in patterns matching the adoption curve.</p><h3 id="cost-efficiency" tabindex="-1">Cost Efficiency <a class="header-anchor" href="#cost-efficiency" aria-label="Permalink to &quot;Cost Efficiency&quot;">‚Äã</a></h3><ul><li>Per-token costs tracked by model</li><li>Per-seat economics derivable from user analytics</li><li><strong>Per-story-point AI cost</strong>: Teams can calculate cost of AI assistance per Linear/Jira story point completed by joining analytics data with project management data.</li></ul><h2 id="benchmark-methodology-observations" tabindex="-1">Benchmark Methodology Observations <a class="header-anchor" href="#benchmark-methodology-observations" aria-label="Permalink to &quot;Benchmark Methodology Observations&quot;">‚Äã</a></h2><h3 id="what-terminal-bench-measures" tabindex="-1">What Terminal-Bench Measures <a class="header-anchor" href="#what-terminal-bench-measures" aria-label="Permalink to &quot;What Terminal-Bench Measures&quot;">‚Äã</a></h3><p>Terminal-Bench evaluates agents on their ability to solve software engineering tasks using terminal tools. This aligns well with Droid&#39;s capabilities since it has a full CLI mode with the same agent core.</p><h3 id="what-enterprise-metrics-measure" tabindex="-1">What Enterprise Metrics Measure <a class="header-anchor" href="#what-enterprise-metrics-measure" aria-label="Permalink to &quot;What Enterprise Metrics Measure&quot;">‚Äã</a></h3><p>Factory&#39;s enterprise metrics focus on <strong>business outcomes</strong> rather than benchmark puzzles:</p><ul><li>Time-to-delivery (feature delivery speed)</li><li>Migration efficiency</li><li>Incident response time</li></ul><p>This reflects Factory&#39;s enterprise positioning ‚Äî they optimize for metrics that matter to engineering leadership and procurement, not just developer satisfaction.</p><h3 id="model-contribution-vs-agent-contribution" tabindex="-1">Model Contribution vs. Agent Contribution <a class="header-anchor" href="#model-contribution-vs-agent-contribution" aria-label="Permalink to &quot;Model Contribution vs. Agent Contribution&quot;">‚Äã</a></h3><p>The multi-model Terminal-Bench entries allow rough estimation of agent vs. model contribution:</p><ul><li>GPT-5.3-Codex alone vs. Droid + GPT-5.3-Codex ‚Üí agent overhead/benefit</li><li>Same agent across multiple models ‚Üí consistency of agent platform value</li></ul><p>The ~7-12 point variation across models with the same agent platform suggests the agent contributes a meaningful but not overwhelming portion of the total score ‚Äî the model still matters significantly.</p>',39)])])}const p=t(i,[["render",n]]);export{u as __pageData,p as default};
